        biometricManager.setBiometricEnabled(enableBiometricSwitch.isOn)
    }
    
    private func performBiometricAuthentication() {
        let biometricType = biometricManager.biometricType
        var reason = ""
        
        switch biometricType {
        case .faceID:
            reason = "Authenticate with Face ID to access your account"
        case .touchID:
            reason = "Authenticate with Touch ID to access your account"
        case .opticID:
            reason = "Authenticate with Optic ID to access your account"
        case .none:
            return
        }
        
        biometricManager.authenticateWithBiometrics(reason: reason) { [weak self] result in
            guard let self = self else { return }
            
            switch result {
            case .success:
                self.navigateToHome()
                
            case .failure(let error):
                self.handleBiometricError(error)
            }
        }
    }
    
    private func handleBiometricError(_ error: BiometricAuthenticationManager.AuthenticationError) {
        switch error {
        case .authenticationFailed:
            showRetryAlert(
                title: "Authentication Failed",
                message: "Biometric authentication failed. Would you like to try again or use your password?"
            )
            
        case .userCanceled:
            break
            
        case .userFallback:
            showPasswordPrompt()
            
        case .biometricLockout:
            showPasscodeUnlockAlert()
            
        case .biometricNotAvailable:
            showAlert(title: "Not Available", message: "Biometric authentication is not available on this device")
            
        case .biometricNotEnrolled:
            showAlert(title: "Not Enrolled", message: "No biometric data is enrolled. Please set up biometrics in Settings")
            
        case .passcodeNotSet:
            showAlert(title: "Passcode Required", message: "Please set up a device passcode in Settings")
            
        case .systemCanceled:
            break
            
        case .unknown:
            showRetryAlert(
                title: "Error",
                message: "An error occurred during authentication. Would you like to try again?"
            )
        }
    }
    
    private func showRetryAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        
        alert.addAction(UIAlertAction(title: "Try Again", style: .default) { [weak self] _ in
            self?.performBiometricAuthentication()
        })
        
        alert.addAction(UIAlertAction(title: "Use Password", style: .default) { [weak self] _ in
            self?.usernameTextField.becomeFirstResponder()
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        present(alert, animated: true)
    }
    
    private func showPasswordPrompt() {
        usernameTextField.becomeFirstResponder()
    }
    
    private func showPasscodeUnlockAlert() {
        let alert = UIAlertController(
            title: "Biometric Locked",
            message: "Biometric authentication is locked due to too many failed attempts. Please unlock with your device passcode.",
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Unlock", style: .default) { [weak self] _ in
            self?.authenticateWithPasscode()
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        present(alert, animated: true)
    }
    
    private func authenticateWithPasscode() {
        biometricManager.authenticateWithDevicePasscode(reason: "Unlock to access your account") { [weak self] result in
            guard let self = self else { return }
            
            switch result {
            case .success:
                self.navigateToHome()
                
            case .failure(let error):
                if error != .userCanceled {
                    self.showAlert(title: "Error", message: "Failed to authenticate with passcode")
                }
            }
        }
    }
    
    private func performLogin(username: String, password: String) {
        if username == "demo" && password == "password" {
            biometricManager.setAuthenticationStatus(true)
            navigateToHome()
        } else {
            showAlert(title: "Login Failed", message: "Invalid username or password")
        }
    }
    
    private func navigateToHome() {
        let homeVC = HomeViewController()
        homeVC.modalPresentationStyle = .fullScreen
        present(homeVC, animated: true)
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

